class Solution:
    def maximumTotalSum(self, maximumHeight):
        heights = sorted(maximumHeight, reverse=True)
        prev = float('inf')
        total = 0
        for h in heights:
            cur = min(h, prev - 1)
            if cur < 1:
                return -1
            total += cur
            prev = cur
        return total

