var maximumTotalSum = function(maximumHeight) {
    const heights = maximumHeight.slice().sort((a, b) => b - a);
    let prev = Infinity;
    let total = 0;
    for (const h of heights) {
        const cur = Math.min(h, prev - 1);
        if (cur < 1) return -1;
        total += cur;
        prev = cur;
    }
    return total;
};
